export function Icon({
  name,
  ...props
}: { name: keyof typeof Icons } & IconProps) {
  const Comp = Icons[name];
  if (!Comp) {
    console.warn(`Icon "${name}" not found — add SVG & re-run generate`);
    return null;
  }
  return <Comp {...props} />;
}
